:root {
    /* Colors */
    --color-primary: ${1:#3b82f6};
    --color-primary-dark: ${2:#1d4ed8};
    --color-primary-light: ${3:#93c5fd};

    --color-secondary: ${4:#64748b};
    --color-accent: ${5:#f59e0b};

    --color-text: ${6:#0f172a};
    --color-text-muted: ${7:#64748b};
    --color-text-inverse: ${8:#ffffff};

    --color-background: ${9:#ffffff};
    --color-background-alt: ${10:#f8fafc};
    --color-surface: ${11:#ffffff};

    --color-border: ${12:#e2e8f0};
    --color-border-hover: ${13:#cbd5e1};

    --color-success: ${14:#10b981};
    --color-warning: ${15:#f59e0b};
    --color-error: ${16:#ef4444};
    --color-info: ${17:#3b82f6};

    /* Typography */
    --font-family-base: ${18:'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif};
    --font-family-heading: ${19:var(--font-family-base)};
    --font-family-mono: ${20:'JetBrains Mono', 'Fira Code', Consolas, monospace};

    --font-size-xs: ${21:0.75rem};
    --font-size-sm: ${22:0.875rem};
    --font-size-base: ${23:1rem};
    --font-size-lg: ${24:1.125rem};
    --font-size-xl: ${25:1.25rem};
    --font-size-2xl: ${26:1.5rem};
    --font-size-3xl: ${27:1.875rem};
    --font-size-4xl: ${28:2.25rem};

    --font-weight-normal: ${29:400};
    --font-weight-medium: ${30:500};
    --font-weight-semibold: ${31:600};
    --font-weight-bold: ${32:700};

    --line-height-tight: ${33:1.25};
    --line-height-normal: ${34:1.5};
    --line-height-relaxed: ${35:1.75};

    /* Spacing */
    --spacing-xs: ${36:0.25rem};
    --spacing-sm: ${37:0.5rem};
    --spacing-md: ${38:1rem};
    --spacing-lg: ${39:1.5rem};
    --spacing-xl: ${40:2rem};
    --spacing-2xl: ${41:3rem};
    --spacing-3xl: ${42:4rem};

    /* Border radius */
    --radius-sm: ${43:0.25rem};
    --radius-md: ${44:0.5rem};
    --radius-lg: ${45:0.75rem};
    --radius-xl: ${46:1rem};
    --radius-full: ${47:9999px};

    /* Shadows */
    --shadow-sm: ${48:0 1px 2px 0 rgba(0, 0, 0, 0.05)};
    --shadow-md: ${49:0 4px 6px -1px rgba(0, 0, 0, 0.1), 0 2px 4px -1px rgba(0, 0, 0, 0.06)};
    --shadow-lg: ${50:0 10px 15px -3px rgba(0, 0, 0, 0.1), 0 4px 6px -2px rgba(0, 0, 0, 0.05)};
    --shadow-xl: ${51:0 20px 25px -5px rgba(0, 0, 0, 0.1), 0 10px 10px -5px rgba(0, 0, 0, 0.04)};

    /* Transitions */
    --transition-fast: ${52:150ms ease};
    --transition-normal: ${53:300ms ease};
    --transition-slow: ${54:500ms ease};

    /* Z-index scale */
    --z-dropdown: ${55:1000};
    --z-sticky: ${56:1020};
    --z-fixed: ${57:1030};
    --z-modal-backdrop: ${58:1040};
    --z-modal: ${59:1050};
    --z-popover: ${60:1060};
    --z-tooltip: ${61:1070};
}

/* Dark mode variables */
@media (prefers-color-scheme: dark) {
    :root {
        --color-text: ${62:#f8fafc};
        --color-text-muted: ${63:#94a3b8};
        --color-background: ${64:#0f172a};
        --color-background-alt: ${65:#1e293b};
        --color-surface: ${66:#334155};
        --color-border: ${67:#475569};
        --color-border-hover: ${68:#64748b};
    }
}

.${1:grid-responsive} {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(${2:280px}, 1fr));
    gap: ${3:var(--spacing-lg, 1.5rem)};
    padding: ${4:var(--spacing-md, 1rem)};
}

/* Responsive variations */
@media (max-width: ${5:768px}) {
    .${1:grid-responsive} {
        grid-template-columns: 1fr;
        gap: ${6:var(--spacing-md, 1rem)};
    }
}

@media (min-width: ${7:1200px}) {
    .${1:grid-responsive} {
        grid-template-columns: repeat(auto-fit, minmax(${8:320px}, 1fr));
        max-width: ${9:1200px};
        margin: 0 auto;
    }
}

.${1:flex-container} {
    display: flex;
    flex-direction: ${2:row};
    flex-wrap: ${3:wrap};
    justify-content: ${4:space-between};
    align-items: ${5:stretch};
    gap: ${6:var(--spacing-lg, 1.5rem)};
}

.${1:flex-container} > * {
    flex: ${7:1 1 0%};
    min-width: ${8:0}; /* Prevent flex items from overflowing */
}

/* Responsive stacking */
@media (max-width: ${9:768px}) {
    .${1:flex-container} {
        flex-direction: column;
        align-items: stretch;
    }

    .${1:flex-container} > * {
        flex: none;
    }
}

/* Flex utilities */
.flex-grow {
    flex-grow: 1;
}

.flex-shrink-0 {
    flex-shrink: 0;
}

.flex-basis-auto {
    flex-basis: auto;
}

.${1:sticky-header} {
    position: sticky;
    top: ${2:0};
    z-index: var(--z-sticky, ${3:1020});
    background: var(--color-background, ${4:#ffffff});
    border-bottom: ${5:1px} solid var(--color-border, ${6:#e2e8f0});
    backdrop-filter: ${7:blur(10px)};
    -webkit-backdrop-filter: ${7:blur(10px)};
    transition: ${8:box-shadow 0.3s ease, background-color 0.3s ease};
}

.${1:sticky-header}.scrolled {
    box-shadow: var(--shadow-md, ${9:0 4px 6px -1px rgba(0, 0, 0, 0.1)});
    background: ${10:rgba(255, 255, 255, 0.9)};
}

/* Smooth scrolling */
html {
    scroll-behavior: smooth;
    scroll-padding-top: ${11:80px}; /* Account for sticky header height */
}

.${1:card} {
    background: var(--color-surface, ${2:#ffffff});
    border-radius: var(--radius-lg, ${3:0.75rem});
    border: ${4:1px} solid var(--color-border, ${5:#e2e8f0});
    box-shadow: var(--shadow-sm, ${6:0 1px 2px 0 rgba(0, 0, 0, 0.05)});
    padding: var(--spacing-lg, ${7:1.5rem});
    transition: var(--transition-normal, ${8:300ms ease});
    position: relative;
    overflow: hidden;
}

.${1:card}::before {
    content: '';
    position: absolute;
    top: 0;
    left: -100%;
    width: 100%;
    height: 100%;
    background: linear-gradient(
        90deg,
        transparent,
        rgba(255, 255, 255, 0.4),
        transparent
    );
    transition: left 0.5s ease;
}

.${1:card}:hover {
    transform: ${9:translateY(-4px)};
    box-shadow: var(--shadow-lg, ${10:0 10px 15px -3px rgba(0, 0, 0, 0.1)});
    border-color: var(--color-border-hover, ${11:#cbd5e1});
}

.${1:card}:hover::before {
    left: 100%;
}

.${1:card}:active {
    transform: ${12:translateY(-2px)};
}

/* Card variants */
.${1:card}--elevated {
    box-shadow: var(--shadow-md, ${13:0 4px 6px -1px rgba(0, 0, 0, 0.1)});
}

.${1:card}--outlined {
    border: ${14:2px} solid var(--color-border, ${5:#e2e8f0});
    box-shadow: none;
}

.${1:card}--filled {
    background: var(--color-background-alt, ${15:#f8fafc});
    border: none;
}

.${1:btn} {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    gap: ${2:0.5rem};
    padding: ${3:0.75rem 1.5rem};
    border: ${4:1px solid transparent};
    border-radius: var(--radius-md, ${5:0.5rem});
    font-family: inherit;
    font-size: var(--font-size-base, ${6:1rem});
    font-weight: var(--font-weight-medium, ${7:500});
    line-height: ${8:1.2};
    text-decoration: none;
    cursor: pointer;
    transition: var(--transition-fast, ${9:150ms ease});
    user-select: none;
    white-space: nowrap;
    position: relative;
    overflow: hidden;
}

.${1:btn}:focus-visible {
    outline: ${10:2px} solid var(--color-primary, ${11:#3b82f6});
    outline-offset: ${12:2px};
}

.${1:btn}:disabled {
    opacity: ${13:0.6};
    cursor: not-allowed;
    pointer-events: none;
}

/* Primary button */
.${1:btn}--primary {
    background: var(--color-primary, ${11:#3b82f6});
    color: var(--color-text-inverse, ${14:#ffffff});
}

.${1:btn}--primary:hover {
    background: var(--color-primary-dark, ${15:#1d4ed8});
    transform: ${16:translateY(-1px)};
}

.${1:btn}--primary:active {
    transform: ${17:translateY(0)};
}

/* Secondary button */
.${1:btn}--secondary {
    background: transparent;
    color: var(--color-primary, ${11:#3b82f6});
    border-color: var(--color-primary, ${11:#3b82f6});
}

.${1:btn}--secondary:hover {
    background: var(--color-primary, ${11:#3b82f6});
    color: var(--color-text-inverse, ${14:#ffffff});
}

/* Ghost button */
.${1:btn}--ghost {
    background: transparent;
    color: var(--color-text, ${18:#0f172a});
}

.${1:btn}--ghost:hover {
    background: var(--color-background-alt, ${19:#f8fafc});
}

/* Size variants */
.${1:btn}--sm {
    padding: ${20:0.5rem 1rem};
    font-size: var(--font-size-sm, ${21:0.875rem});
}

.${1:btn}--lg {
    padding: ${22:1rem 2rem};
    font-size: var(--font-size-lg, ${23:1.125rem});
}

/* Icon button */
.${1:btn}--icon {
    padding: ${24:0.75rem};
    aspect-ratio: 1;
}

/* Loading state */
.${1:btn}--loading {
    color: transparent;
}

.${1:btn}--loading::after {
    content: '';
    position: absolute;
    top: 50%;
    left: 50%;
    width: ${25:1rem};
    height: ${25:1rem};
    margin: ${26:-0.5rem 0 0 -0.5rem};
    border: ${27:2px} solid currentColor;
    border-radius: 50%;
    border-top-color: transparent;
    animation: ${28:spin 1s linear infinite};
}

@keyframes ${28:spin} {
    to {
        transform: rotate(360deg);
    }
}

.${1:form-group} {
    margin-bottom: var(--spacing-lg, ${2:1.5rem});
}

.${1:form-label} {
    display: block;
    font-size: var(--font-size-sm, ${3:0.875rem});
    font-weight: var(--font-weight-medium, ${4:500});
    color: var(--color-text, ${5:#0f172a});
    margin-bottom: ${6:0.5rem};
}

.${1:form-input} {
    display: block;
    width: 100%;
    padding: ${7:0.75rem 1rem};
    border: ${8:1px} solid var(--color-border, ${9:#e2e8f0});
    border-radius: var(--radius-md, ${10:0.5rem});
    background: var(--color-background, ${11:#ffffff});
    font-family: inherit;
    font-size: var(--font-size-base, ${12:1rem});
    line-height: ${13:1.5};
    color: var(--color-text, ${5:#0f172a});
    transition: var(--transition-fast, ${14:150ms ease});
}

.${1:form-input}::placeholder {
    color: var(--color-text-muted, ${15:#64748b});
}

.${1:form-input}:focus {
    outline: none;
    border-color: var(--color-primary, ${16:#3b82f6});
    box-shadow: ${17:0 0 0 3px rgba(59, 130, 246, 0.1)};
}

.${1:form-input}:hover {
    border-color: var(--color-border-hover, ${18:#cbd5e1});
}

/* Input states */
.${1:form-input}--error {
    border-color: var(--color-error, ${19:#ef4444});
}

.${1:form-input}--error:focus {
    border-color: var(--color-error, ${19:#ef4444});
    box-shadow: ${20:0 0 0 3px rgba(239, 68, 68, 0.1)};
}

.${1:form-input}--success {
    border-color: var(--color-success, ${21:#10b981});
}

.${1:form-input}:disabled {
    background: ${22:#f8fafc};
    color: ${23:#94a3b8};
    cursor: not-allowed;
    opacity: ${24:0.6};
}

/* Error message */
.${1:form-error} {
    display: block;
    margin-top: ${25:0.25rem};
    font-size: var(--font-size-xs, ${26:0.75rem});
    color: var(--color-error, ${19:#ef4444});
}

/* Help text */
.${1:form-help} {
    display: block;
    margin-top: ${27:0.25rem};
    font-size: var(--font-size-xs, ${26:0.75rem});
    color: var(--color-text-muted, ${15:#64748b});
}

.${1:nav} {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: var(--spacing-md, ${2:1rem}) var(--spacing-lg, ${3:1.5rem});
    background: var(--color-background, ${4:#ffffff});
    border-bottom: ${5:1px} solid var(--color-border, ${6:#e2e8f0});
}

.${1:nav}__brand {
    font-size: var(--font-size-xl, ${7:1.25rem});
    font-weight: var(--font-weight-bold, ${8:700});
    color: var(--color-text, ${9:#0f172a});
    text-decoration: none;
}

.${1:nav}__menu {
    display: flex;
    align-items: center;
    gap: var(--spacing-lg, ${3:1.5rem});
    list-style: none;
    margin: 0;
    padding: 0;
}

.${1:nav}__link {
    color: var(--color-text-muted, ${10:#64748b});
    text-decoration: none;
    font-weight: var(--font-weight-medium, ${11:500});
    transition: var(--transition-fast, ${12:150ms ease});
    position: relative;
}

.${1:nav}__link:hover,
.${1:nav}__link--active {
    color: var(--color-primary, ${13:#3b82f6});
}

.${1:nav}__link--active::after {
    content: '';
    position: absolute;
    bottom: ${14:-8px};
    left: 0;
    right: 0;
    height: ${15:2px};
    background: var(--color-primary, ${13:#3b82f6});
    border-radius: ${16:1px};
}

/* Mobile menu toggle */
.${1:nav}__toggle {
    display: none;
    background: none;
    border: none;
    cursor: pointer;
    padding: ${17:0.5rem};
    color: var(--color-text, ${9:#0f172a});
}

.${1:nav}__toggle-icon {
    width: ${18:1.5rem};
    height: ${19:1.5rem};
    display: flex;
    flex-direction: column;
    justify-content: space-between;
}

.${1:nav}__toggle-icon span {
    display: block;
    height: ${20:2px};
    background: currentColor;
    transition: var(--transition-fast, ${12:150ms ease});
    transform-origin: center;
}

/* Mobile styles */
@media (max-width: ${21:768px}) {
    .${1:nav}__toggle {
        display: block;
    }

    .${1:nav}__menu {
        position: absolute;
        top: 100%;
        left: 0;
        right: 0;
        background: var(--color-background, ${4:#ffffff});
        border-top: ${5:1px} solid var(--color-border, ${6:#e2e8f0});
        flex-direction: column;
        padding: var(--spacing-md, ${2:1rem});
        transform: ${22:translateY(-100%)};
        opacity: ${23:0};
        visibility: hidden;
        transition: var(--transition-normal, ${24:300ms ease});
    }

    .${1:nav}__menu--open {
        transform: ${25:translateY(0)};
        opacity: ${26:1};
        visibility: visible;
    }

    .${1:nav}__link {
        display: block;
        padding: var(--spacing-sm, ${27:0.5rem}) 0;
        border-bottom: ${28:1px} solid var(--color-border, ${6:#e2e8f0});
    }

    .${1:nav}__link:last-child {
        border-bottom: none;
    }

    /* Hamburger animation */
    .${1:nav}__toggle--active .${1:nav}__toggle-icon span:nth-child(1) {
        transform: ${29:rotate(45deg) translate(5px, 5px)};
    }

    .${1:nav}__toggle--active .${1:nav}__toggle-icon span:nth-child(2) {
        opacity: ${30:0};
    }

    .${1:nav}__toggle--active .${1:nav}__toggle-icon span:nth-child(3) {
        transform: ${31:rotate(-45deg) translate(5px, -5px)};
    }
}

.${1:modal} {
    position: fixed;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    z-index: var(--z-modal, ${2:1050});
    display: flex;
    align-items: center;
    justify-content: center;
    padding: var(--spacing-lg, ${3:1.5rem});
    opacity: 0;
    visibility: hidden;
    transition: var(--transition-normal, ${4:300ms ease});
}

.${1:modal}--open {
    opacity: 1;
    visibility: visible;
}

.${1:modal}__backdrop {
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    background: ${5:rgba(0, 0, 0, 0.5)};
    backdrop-filter: ${6:blur(4px)};
    -webkit-backdrop-filter: ${6:blur(4px)};
}

.${1:modal}__content {
    position: relative;
    background: var(--color-surface, ${7:#ffffff});
    border-radius: var(--radius-lg, ${8:0.75rem});
    box-shadow: var(--shadow-xl, ${9:0 20px 25px -5px rgba(0, 0, 0, 0.1)});
    width: 100%;
    max-width: ${10:500px};
    max-height: ${11:90vh};
    overflow: hidden;
    transform: ${12:scale(0.9)};
    transition: var(--transition-normal, ${4:300ms ease});
}

.${1:modal}--open .${1:modal}__content {
    transform: ${13:scale(1)};
}

.${1:modal}__header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: var(--spacing-lg, ${3:1.5rem});
    border-bottom: ${14:1px} solid var(--color-border, ${15:#e2e8f0});
}

.${1:modal}__title {
    margin: 0;
    font-size: var(--font-size-xl, ${16:1.25rem});
    font-weight: var(--font-weight-semibold, ${17:600});
    color: var(--color-text, ${18:#0f172a});
}

.${1:modal}__close {
    background: none;
    border: none;
    padding: ${19:0.5rem};
    cursor: pointer;
    color: var(--color-text-muted, ${20:#64748b});
    transition: var(--transition-fast, ${21:150ms ease});
    border-radius: var(--radius-sm, ${22:0.25rem});
}

.${1:modal}__close:hover {
    background: var(--color-background-alt, ${23:#f8fafc});
    color: var(--color-text, ${18:#0f172a});
}

.${1:modal}__body {
    padding: var(--spacing-lg, ${3:1.5rem});
    overflow-y: auto;
    max-height: ${24:60vh};
}

.${1:modal}__footer {
    display: flex;
    align-items: center;
